        "Description" text NOT NULL,
        "Division" text NOT NULL,
        "Status" integer NOT NULL,
        "ImpactScore" integer NOT NULL,
        "FeasibilityScore" integer NOT NULL,
        "AlignmentScore" integer NOT NULL,
        "EvidenceUrl" text,
        "CreatedAt" timestamp with time zone NOT NULL,
        "UpdatedAt" timestamp with time zone NOT NULL,
        "UserId" integer NOT NULL,
        "ChallengId" integer,
        "ChallengeId" integer,
        CONSTRAINT "PK_Idea" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_Idea_Challenge_ChallengeId" FOREIGN KEY ("ChallengeId") REFERENCES "Challenge" ("Id"),
        CONSTRAINT "FK_Idea_User_UserId" FOREIGN KEY ("UserId") REFERENCES "User" ("Id") ON DELETE CASCADE
    );
    END IF;
