        "ManagerId" integer NOT NULL,
        "IdeaId" integer,
        CONSTRAINT "PK_Project" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_Project_Idea_IdeaId" FOREIGN KEY ("IdeaId") REFERENCES "Idea" ("Id"),
